/**
 * gen-card-series.js — 外部 mycryptoheroes/Data/Extensions/extensions.json から
 * 各カードの series 情報を抽出し、CARD_SERIES dict (cards.js 末尾に挿入) を生成する。
 *
 * 使い方:
 *   node prototype/tools/gen-card-series.js [external-extensions.json] > out.txt
 *
 * 引数を省略した場合は GitHub から fetch を試みる (Node 18+ の native fetch 必須)。
 *
 * 出力は cards.js の CARD_RARITIES の後に貼り付けることを想定した dict 形式。
 * 既存 CARD_SERIES があれば手動で置き換えること。
 *
 * 注: 外部 ext.json には series.name.ja が無いカード (5 件程度) があるため、
 *     対象外として skip。CARD_SERIES に該当エントリは作らない (= 上位 rarity
 *     計算から除外される、その場合は upgrade 不可カードとして扱われる)。
 */
const fs = require("fs");
const path = require("path");

async function loadExternalJson(arg) {
  if (arg) return JSON.parse(fs.readFileSync(arg, "utf-8"));
  const url = "https://raw.githubusercontent.com/bearko/mycryptoheroes/main/Data/Extensions/extensions.json";
  console.error("fetching", url);
  const res = await fetch(url);
  if (!res.ok) throw new Error("fetch failed: " + res.status);
  return await res.json();
}

function extractOurExtIds(cardsJsPath) {
  const code = fs.readFileSync(cardsJsPath, "utf-8");
  const ids = [];
  for (const m of code.matchAll(/extId:\s*(\d+)/g)) ids.push(+m[1]);
  return ids;
}

async function main() {
  const externalArg = process.argv[2];
  const cardsJsPath = path.resolve(__dirname, "..", "js", "cards.js");

  const external = await loadExternalJson(externalArg);
  const seriesById = {};
  for (const ext of external) {
    if (ext.series && ext.series.name && ext.series.name.ja) {
      seriesById[ext.id] = ext.series.name.ja;
    }
  }
  const ourIds = extractOurExtIds(cardsJsPath);

  console.error("our cards:", ourIds.length);
  console.error("external entries:", external.length);
  let withSeries = 0;
  const missing = [];
  for (const id of ourIds) {
    if (seriesById[id]) withSeries++;
    else missing.push(id);
  }
  console.error("with series:", withSeries);
  console.error("missing (skipped):", missing.length, missing.length > 0 ? "(" + missing.join(",") + ")" : "");

  // 出力: dict ライク (cards.js 末尾に挿入できる形)
  console.log("/** カードシリーズ情報 (auto-generated by tools/gen-card-series.js)");
  console.log(" *  元データ: bearko/mycryptoheroes/Data/Extensions/extensions.json の series.name.ja");
  console.log(" *  CARD_RARITIES と合わせて findUpgradeKey() の動的計算に使う。 */");
  console.log("export const CARD_SERIES = {");
  for (const id of ourIds) {
    const s = seriesById[id];
    if (!s) continue;
    const key = "ext" + id;
    // ' を escape
    const safe = s.replace(/'/g, "\\'");
    console.log(`  ${key}: '${safe}',`);
  }
  console.log("};");
}

main().catch(e => { console.error(e); process.exit(1); });
